import axios from "axios";

const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || "http://localhost:8080",
  timeout: 8000
});

function formatServerMessage(err) {
  const data = err?.response?.data;
  if (!data) return err.message || "Unknown error";
  if (typeof data === "string") return data;
  if (data.message && typeof data.message === "string") return data.message;
  // handle validation style objects: { field: ["err1","err2"] } or list of errors
  if (typeof data === "object") {
    // try common shapes
    if (Array.isArray(data)) return data.map(String).join("; ");
    if (data.errors && typeof data.errors === "object") {
      return Object.values(data.errors).flat().join("; ");
    }
    // fallback to JSON
    try { return JSON.stringify(data); } catch (e) { return String(data); }
  }
  return String(data);
}

api.interceptors.response.use(
  (res) => res,
  (err) => {
    const msg = formatServerMessage(err);
    return Promise.reject(new Error(msg));
  }
);

export default api;
export const fetchPatients = () => api.get("/api/patients").then((r) => r.data);
export const fetchDoctors = () => api.get("/api/doctors").then((r) => r.data);
export const createPatient = (data) => api.post("/api/patients", data).then((r) => r.data);
export const createAppointment = (data) => api.post("/api/appointments", data).then((r) => r.data);
export const updateAppointmentStatus = (id, status) => api.patch(`/api/appointments/${id}/status`, { status }).then((r) => r.data);
export const fetchAppointmentsByPatient = (patientId) => api.get(`/api/appointments/patient/${patientId}`).then((r) => r.data);
